  /** Returns all package names for a team's offense */
  export function getOffensePackages(slug: string): string[] {
    return Object.keys(PLAYBOOKS[slug]?.offense ?? {});
  }

  /** Returns all formations in a package for a team's offense */
  export function getOffenseFormations(slug: string, pkg: string): string[] {
    return Object.keys(PLAYBOOKS[slug]?.offense?.[pkg] ?? {});
  }

  /** Returns all plays in a formation for a team's offense */
  export function getOffensePlays(slug: string, pkg: string, formation: string): string[] {
    return PLAYBOOKS[slug]?.offense?.[pkg]?.[formation] ?? [];
  }

  /** Returns all package names for a team's defense */
  export function getDefensePackages(slug: string): string[] {
    return Object.keys(PLAYBOOKS[slug]?.defense ?? {});
  }

  /** Returns all formations in a package for a team's defense */
  export function getDefenseFormations(slug: string, pkg: string): string[] {
    return Object.keys(PLAYBOOKS[slug]?.defense?.[pkg] ?? {});
  }

  /** Returns all plays in a formation for a team's defense */
  export function getDefensePlays(slug: string, pkg: string, formation: string): string[] {
    return PLAYBOOKS[slug]?.defense?.[pkg]?.[formation] ?? [];
  }

